/**
 * 302.ai WhisperX 语音转文字 API 测试
 * 支持带时间戳的解析结果（segments 含 start/end）
 *
 * 传入音频 base64（优先级从高到低）：
 *   1. 下方 AUDIO_BASE64 常量（在文件中写死）
 *   2. 命令行参数：node whisperx.test.js <base64>
 *   3. 环境变量：AUDIO_BASE64=<base64> node whisperx.test.js
 */

import "dotenv/config";
import FormData from "form-data";

/** 音频格式（当 base64 为纯字符串、非 data URI 时使用）：wav | mp3 | m4a */
const AUDIO_FORMAT = "mp3";

/** 处理模式：diarize=utterances（按说话人分段）| align（词级对齐） */
const PROCESSING_MODE = "diarize";

/** 在此处写入音频 base64，或 data URI（data:audio/wav;base64,...）*/
const AUDIO_BASE64=""
const AI_BASE_URL = process.env.AI_BASE_URL || "https://api.302.ai";
const AI_API_KEY = process.env.AI_API_KEY;

if (!AI_API_KEY) {
  console.error("❌ 未设置 AI_API_KEY，请在 .env 中配置");
  process.exit(1);
}

const WHISPERX_URL = `${AI_BASE_URL.replace(/\/$/, "")}/302/whisperx`;

function parseAudioBase64() {
  const base64 = (AUDIO_BASE64 || process.env.AUDIO_BASE64 || process.argv[2] || "").trim();

  if (!base64) {
    console.error("❌ 请在文件顶部 AUDIO_BASE64 中写入 base64，或通过命令行/环境变量传入");
    process.exit(1);
  }

  // 支持 data URI：data:audio/wav;base64,xxx
  const match = base64.match(/^data:audio\/(\w+);base64,(.+)$/);
  const b64 = match ? match[2] : base64;
  const formatMap = { wav: "audio/wav", mp3: "audio/mpeg", m4a: "audio/mp4" };
  const ext = match ? (match[1] === "x-wav" ? "wav" : match[1]) : AUDIO_FORMAT;
  const mime = match ? `audio/${match[1]}` : (formatMap[AUDIO_FORMAT] || "audio/mpeg");

  try {
    return { buffer: Buffer.from(b64, "base64"), ext, mime };
  } catch {
    console.error("❌ base64 解码失败");
    process.exit(1);
  }
}

/**
 * 调用 WhisperX API
 */
async function whisperx(audioBuffer, options = {}) {
  const { ext, mime } = options;
  const form = new FormData();
  form.append("audio_input", audioBuffer, {
    filename: `audio.${ext}`,
    contentType: mime,
  });
  form.append("processing_type", options.processing_type || PROCESSING_MODE);
  form.append("output", options.output || "raw");

  if (options.language) form.append("language", options.language);
  if (options.translate !== undefined) form.append("translate", options.translate);

  const res = await fetch(WHISPERX_URL, {
    method: "POST",
    headers: {
      ...form.getHeaders(),
      Authorization: `Bearer ${AI_API_KEY}`,
    },
    body: form.getBuffer ? form.getBuffer() : await streamToBuffer(form),
  });

  if (!res.ok) {
    const text = await res.text();
    throw new Error(`HTTP ${res.status}: ${text}`);
  }

  return res.json();
}

async function streamToBuffer(form) {
  return new Promise((resolve, reject) => {
    const chunks = [];
    form.on("data", (c) => chunks.push(c));
    form.on("end", () => resolve(Buffer.concat(chunks)));
    form.on("error", reject);
  });
}

/**
 * 格式化时间戳（秒 -> mm:ss.sss）
 */
function formatTimestamp(sec) {
  const m = Math.floor(sec / 60);
  const s = (sec % 60).toFixed(3);
  return `${m.toString().padStart(2, "0")}:${s.padStart(6, "0")}`;
}

async function run() {
  console.log("302.ai WhisperX 语音转文字 API 测试");
  console.log("Base URL:", AI_BASE_URL);

  const { buffer: audioBuffer, ext, mime } = parseAudioBase64();
  console.log("\n使用传入的 base64 音频, 格式:", mime);

  console.log("--- 请求参数 ---");
  console.log("processing_type:", PROCESSING_MODE, "(utterances 模式)");
  console.log("output: raw（带时间戳）");

  try {
    const data = await whisperx(audioBuffer, {
      ext,
      mime,
      processing_type: PROCESSING_MODE,
      output: "raw",
    });

    const { usage, segments, subtitles, error } = data;

    if (error) {
      console.error("❌ API 返回错误:", error);
      process.exit(1);
    }

    console.log("\n--- 使用统计 ---");
    if (usage) {
      console.log("输入音频时长:", usage.input_audio_length, "秒");
      console.log("耗时:", usage.elapsed_time, "秒");
      console.log("推理类型:", usage.inference_type ?? "(无)");
    }

    console.log("\n--- 带时间戳的解析结果 (utterances) ---");
    if (segments && segments.length > 0) {
      segments.forEach((seg, i) => {
        const start = formatTimestamp(seg.start ?? 0);
        const end = formatTimestamp(seg.end ?? 0);
        const text = seg.text?.trim() || "(空)";
        const speaker = seg.speaker != null ? ` [${seg.speaker}]` : "";
        console.log(`  [${i + 1}] ${start} - ${end}${speaker}: ${text}`);
      });
    } else {
      console.log("  (无识别结果，可能为静音或过短)");
    }

    if (subtitles) {
      console.log("\n--- 字幕 (SRT) ---");
      console.log(subtitles);
    }

    console.log("\n✅ 测试通过");
    process.exit(0);
  } catch (e) {
    console.error("\n❌ 测试失败:", e.message);
    process.exit(1);
  }
}

run();
